const body = $json.body || $json;
const event = body.event || {};
const headers = $json.headers || {};

if (headers['x-slack-retry-num']) return [];

const BOT_USER_ID = 'U07K8QJ9XYZ';

if (event.subtype === 'message_changed') {
  const prev = event.previous_message?.text || '';
  const curr = event.message?.text || '';
  if (prev === curr) return [];

  const extractUrls = (text) => {
    const urls = new Set();
    const slackRx = /<(https?:\/\/[^>|]+)(\|[^>]+)?>/g;
    let m;
    while ((m = slackRx.exec(text)) !== null) urls.add(m[1]);
    const plainRx = /https?:\/\/[^\s<>"'\[\]{}|]+/g;
    while ((m = plainRx.exec(text)) !== null) urls.add(m[0].replace(/[.,;:)]+$/, ''));
    return urls;
  };

  const prevUrls = extractUrls(prev);
  const currUrls = extractUrls(curr);
  const newUrls = [...currUrls].map(u => u.split('|')[0]).filter(u => !prevUrls.has(u) && u.match(/^https?:\/\/.+\..+/));

  if (newUrls.length === 0) return [];

  const user = event.message?.user || event.previous_message?.user || '';
  if (!user || user === BOT_USER_ID || event.message?.bot_id) return [];

  const staticData = $getWorkflowStaticData('global');
  if (!staticData.processedUrls) staticData.processedUrls = {};
  if (!staticData.processedMsgs) staticData.processedMsgs = {};

  const msgKey = `${user}_${event.message?.ts || event.ts}_edited`;
  if (staticData.processedMsgs[msgKey]) return [];
  staticData.processedMsgs[msgKey] = Date.now();

  const twoDaysAgo = Date.now() - 172800000;
  for (const k of Object.keys(staticData.processedUrls)) if (staticData.processedUrls[k] < twoDaysAgo) delete staticData.processedUrls[k];
  for (const k of Object.keys(staticData.processedMsgs)) if (staticData.processedMsgs[k] < twoDaysAgo) delete staticData.processedMsgs[k];

  const results = [];
  const fourHoursAgo = Date.now() - 14400000;
  for (const url of newUrls) {
    const isDuplicate = staticData.processedUrls[url] > fourHoursAgo;
    if (!isDuplicate) staticData.processedUrls[url] = Date.now();
    const slack_ts = event.message?.ts || event.ts;
    const slack_thread_ts = event.message?.thread_ts || null;
    results.push({ json: { isDuplicate, url, slack_channel: event.channel, slack_user: user, slack_ts, slack_thread_ts } });
  }
  return results;
}

const skipSubtypes = ['bot_message','message_deleted','channel_join','channel_leave','channel_topic','channel_purpose','file_share','pinned_item','unpinned_item'];
if (event.subtype && skipSubtypes.includes(event.subtype)) return [];
if (event.type !== 'message' || event.bot_id || event.user === BOT_USER_ID || !event.text) return [];

const text = event.text || '';
const urls = new Set();
const slackRx = /<(https?:\/\/[^>|]+)(\|[^>]+)?>/g;
let m;
while ((m = slackRx.exec(text)) !== null) urls.add(m[1]);
const plainRx = /https?:\/\/[^\s<>"'\[\]{}|]+/g;
while ((m = plainRx.exec(text)) !== null) urls.add(m[0].replace(/[.,;:)]+$/, ''));

const validUrls = [...urls].map(u => u.split('|')[0]).filter(u => u.match(/^https?:\/\/.+\..+/));
if (validUrls.length === 0) return [];

const staticData = $getWorkflowStaticData('global');
if (!staticData.processedUrls) staticData.processedUrls = {};
if (!staticData.processedMsgs) staticData.processedMsgs = {};

const msgKey = `${event.user}_${event.ts}`;
if (staticData.processedMsgs[msgKey]) return [];
staticData.processedMsgs[msgKey] = Date.now();

const fourHoursAgo = Date.now() - 14400000;
const twoDaysAgo = Date.now() - 172800000;
for (const k of Object.keys(staticData.processedUrls)) if (staticData.processedUrls[k] < twoDaysAgo) delete staticData.processedUrls[k];
for (const k of Object.keys(staticData.processedMsgs)) if (staticData.processedMsgs[k] < twoDaysAgo) delete staticData.processedMsgs[k];

const results = [];
for (const url of validUrls) {
  const isDuplicate = staticData.processedUrls[url] > fourHoursAgo;
  if (!isDuplicate) staticData.processedUrls[url] = Date.now();
  const slack_ts = event.ts;
  const slack_thread_ts = event.thread_ts || null;
  results.push({ json: { isDuplicate, url, slack_channel: event.channel, slack_user: event.user, slack_ts, slack_thread_ts } });
}
return results;

const url = $('Is Duplicate?1').first().json.url || '';
const slack_channel = $('Is Duplicate?1').first().json.slack_channel || '';
const slack_ts = $('Is Duplicate?1').first().json.slack_ts || '';
const slack_thread_ts = $('Is Duplicate?1').first().json.slack_thread_ts || null;

// Handle fetch-level errors (network failure, DNS, etc.)
if ($json.error) {
  return [{ json: { needsJina: true, url, slack_channel, slack_ts, slack_thread_ts, error: `Fetch error: ${$json.error}` } }];
}

const status = $json.statusCode || 200;
const JINA_STATUSES = [401, 403, 404, 429, 451, 500, 502, 503, 504];

if (JINA_STATUSES.includes(status)) {
  return [{ json: { needsJina: true, url, slack_channel, slack_ts, slack_thread_ts, error: `HTTP ${status} — direct fetch blocked` } }];
}

// Pass through with context fields appended
return [{ json: { ...$json, url, slack_channel, slack_ts, slack_thread_ts } }];

const headers = $json.headers || {};
const contentType = (headers['content-type'] || headers['Content-Type'] || '').toLowerCase();
const url = $json.url || $('Is Duplicate?1').first().json.url || '';
const slack_channel = $json.slack_channel || $('Is Duplicate?1').first().json.slack_channel || '';
const slack_ts = $json.slack_ts || $('Is Duplicate?1').first().json.slack_ts || '';
const slack_thread_ts = $json.slack_thread_ts || $('Is Duplicate?1').first().json.slack_thread_ts || null;

const decodeEntities = (str) => str
  .replace(/&quot;/g, '"').replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>')
  .replace(/&#39;/g, "'").replace(/&apos;/g, "'").replace(/&#x27;/g, "'")
  .replace(/&#(\d+);/g, (_, n) => String.fromCharCode(Number(n)));

// If routed here because of a jina-needed flag, pass straight through
if ($json.needsJina) {
  return [{ json: { needsJina: true, url, slack_channel, slack_ts, slack_thread_ts, error: $json.error || 'Direct fetch blocked' } }];
}

if (contentType && !contentType.includes('text/html') && !contentType.includes('application/xhtml') && !contentType.includes('text/plain')) {
  return [{ json: { error: `Non-HTML content (${contentType.split(';')[0]}). Cannot extract article text.`, url, slack_channel, slack_ts, slack_thread_ts, needsJina: false } }];
}
const html = $json.body || $json.data || $json.html || $json.content || '';
if (!html || (typeof html === 'string' && html.length < 100)) {
  return [{ json: { error: 'No HTML content received', url, slack_channel, slack_ts, slack_thread_ts, needsJina: true } }];
}
const MAX_LEN = 12000;
let text = '';
try {
  const ld = html.match(/<script[^>]*type=["']application\/ld\+json["'][^>]*>([\s\S]*?)<\/script>/i);
  if (ld) { const d = JSON.parse(ld[1]); if (d.articleBody && d.articleBody.length > 300) text = d.articleBody; }
} catch (e) {}
if (text.length < 300) {
  const art = html.match(/<article[^>]*>([\s\S]*?)<\/article>/i);
  if (art) {
    const ex = art[1].replace(/<script[\s\S]*?<\/script>/gi,'').replace(/<style[\s\S]*?<\/style>/gi,'').replace(/<nav[\s\S]*?<\/nav>/gi,'').replace(/<aside[\s\S]*?<\/aside>/gi,'').replace(/<footer[\s\S]*?<\/footer>/gi,'').replace(/<[^>]+>/g,' ').replace(/\s+/g,' ').trim();
    if (ex.length > text.length) text = ex;
  }
}
if (text.length < 300) {
  const main = html.match(/<main[^>]*>([\s\S]*?)<\/main>/i);
  if (main) {
    const ex = main[1].replace(/<script[\s\S]*?<\/script>/gi,'').replace(/<style[\s\S]*?<\/style>/gi,'').replace(/<nav[\s\S]*?<\/nav>/gi,'').replace(/<[^>]+>/g,' ').replace(/\s+/g,' ').trim();
    if (ex.length > text.length) text = ex;
  }
}
if (text.length < 300) {
  const pat = /<div[^>]*class="[^"]*(?:art_body|article_text|article-body|post-content|entry-content|story-body|article__content|content-body)[^"]*"[^>]*>([\s\S]*?)<\/div>/i;
  const match = html.match(pat);
  if (match) { const ex = match[1].replace(/<[^>]+>/g,' ').replace(/\s+/g,' ').trim(); if (ex.length > text.length) text = ex; }
}
if (text.length < 300) {
  const paras = html.match(/<p[^>]*>(.*?)<\/p>/gis);
  if (paras && paras.length > 3) {
    const good = paras.map(p => p.replace(/<[^>]+>/g,'').trim()).filter(p => p.length > 40 && !/cookie|privacy|subscribe|newsletter|הרשמה|פרטיות/i.test(p));
    if (good.length >= 3) text = good.join('\n\n');
  }
}
text = text.replace(/all rights reserved|כל הזכויות שמורות|copyright \d{4}|©\s*\d{4}/gi,'').replace(/follow us on.*|עקבו אחרינו.*/gi,'').replace(/\s+/g,' ').trim();
if (!text || text.length < 200) {
  return [{ json: { error: 'Direct extraction failed', url, slack_channel, slack_ts, slack_thread_ts, needsJina: true } }];
}

// Shared language detection
const israeliSites = ['walla.co.il','ynet.co.il','mako.co.il','haaretz.co.il','calcalist.co.il','globes.co.il','maariv.co.il','sport5.co.il','kan.org.il','n12.co.il','reshet13.co.il','ice.co.il','arutz7.co.il','hidabroot.com'];
const russianSites = ['rbc.ru','lenta.ru','ria.ru','tass.ru','kommersant.ru','meduza.io','novayagazeta.ru','iz.ru'];
let language = 'en';
if (israeliSites.some(s => url.includes(s))) language = 'he';
else if (russianSites.some(s => url.includes(s))) language = 'ru';
else {
  const heb = (text.match(/[\u0590-\u05FF]/g) || []).length;
  const cyr = (text.match(/[\u0400-\u04FF]/g) || []).length;
  const total = text.length;
  if (heb / total > 0.08) language = 'he';
  else if (cyr / total > 0.08) language = 'ru';
}
text = decodeEntities(text);
if (text.length > MAX_LEN) text = text.substring(0, MAX_LEN) + '... [truncated]';
return [{ json: { article: text, url, language, charCount: text.length, needsJina: false, slack_channel, slack_ts, slack_thread_ts } }];

const raw = $json.data || $json.body || $json.content || '';
const prevData = $('Needs Jina Fallback?1').first().json;
const url = prevData.url || '';
const slack_channel = prevData.slack_channel || '';
const slack_ts = prevData.slack_ts || '';
const slack_thread_ts = prevData.slack_thread_ts || null;

if (!raw || (typeof raw === 'string' && raw.length < 200)) {
  let reason = prevData.error || 'Could not extract article text.';
  if (reason === 'Direct extraction failed') reason += ' Jina Reader also failed — site may require login or block automated access.';
  return [{ json: { error: reason, url, slack_channel, slack_ts, slack_thread_ts, needsJina: false } }];
}

let text = typeof raw === 'string' ? raw : JSON.stringify(raw);
const MAX_LEN = 12000;

text = text.replace(/^Title:.*\n/i, '').replace(/^URL Source:.*\n/i, '').replace(/^Markdown Content:\n/i, '').replace(/!\[.*?\]\(.*?\)/g, '').replace(/\[([^\]]+)\]\(.*?\)/g, '$1').replace(/#{1,6}\s*/g, '').replace(/[*_]{1,3}/g, '').replace(/\s+/g, ' ').trim();
text = text.replace(/all rights reserved|כל הזכויות שמורות|copyright \d{4}|©\s*\d{4}/gi,'').replace(/follow us on.*|עקבו אחרינו.*/gi,'').replace(/\s+/g,' ').trim();

const israeliSites = ['walla.co.il','ynet.co.il','mako.co.il','haaretz.co.il','calcalist.co.il','globes.co.il','maariv.co.il','sport5.co.il','kan.org.il','n12.co.il','reshet13.co.il','ice.co.il','arutz7.co.il','hidabroot.com'];
const russianSites = ['rbc.ru','lenta.ru','ria.ru','tass.ru','kommersant.ru','meduza.io','novayagazeta.ru','iz.ru'];

let language = 'en';
if (israeliSites.some(s => url.includes(s))) language = 'he';
else if (russianSites.some(s => url.includes(s))) language = 'ru';
else {
  const heb = (text.match(/[\u0590-\u05FF]/g) || []).length;
  const cyr = (text.match(/[\u0400-\u04FF]/g) || []).length;
  const total = text.length;
  if (heb / total > 0.08) language = 'he';
  else if (cyr / total > 0.08) language = 'ru';
}

if (text.length > MAX_LEN) text = text.substring(0, MAX_LEN) + '... [truncated]';
return [{ json: { article: text, url, language, charCount: text.length, needsJina: false, slack_channel, slack_ts, slack_thread_ts } }];

let raw = $json.output || $json.text || $json.content || '';
if (typeof raw !== 'string') raw = JSON.stringify(raw);

const url = $('Build Prompt1').first().json.url || '';
const language = $('Build Prompt1').first().json.language || 'en';
const slack_channel = $('Build Prompt1').first().json.slack_channel || '';
const slack_ts = $('Build Prompt1').first().json.slack_ts || '';
const slack_thread_ts = $('Build Prompt1').first().json.slack_thread_ts || null;

const decodeEntities = (str) => str
  .replace(/&quot;/g, '"').replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>')
  .replace(/&#39;/g, "'").replace(/&apos;/g, "'").replace(/&#x27;/g, "'")
  .replace(/&#(\d+);/g, (_, n) => String.fromCharCode(Number(n)));

try {
  const unwrapped = JSON.parse(raw);
  if (typeof unwrapped === 'string') raw = unwrapped;
} catch (e) {}

raw = raw.replace(/<think>[\s\S]*?<\/think>/gi, '').trim();

let s = raw.replace(/```json\s*/gi, '').replace(/```\s*/g, '');

// Escape Hebrew acronym quotes
s = s.replace(/([\u0590-\u05FF])["״\u201C\u201D]([\u0590-\u05FF])/g, '$1\\"$2');

// Merge duplicate bullets keys
if ((s.match(/"bullets"\s*:/g) || []).length > 1) {
  const tm = s.match(/"title"\s*:\s*"((?:[^"\\]|\\.)*)"/);
  const allBullets = [];
  const bulletRx = /"bullets"\s*:\s*\[\s*"((?:[^"\\]|\\.)*)"\s*\]/g;
  let bm;
  while ((bm = bulletRx.exec(s)) !== null) allBullets.push(bm[1]);
  if (tm && allBullets.length > 1) s = JSON.stringify({ title: tm[1], bullets: allBullets });
}

const si = s.indexOf('{');
const ei = s.lastIndexOf('}');
if (si > -1 && ei > si) s = s.substring(si, ei + 1);

s = s.replace(/[\r\n]+/g, ' ').replace(/[\u2018\u2019]/g, "'").replace(/[\u201C\u201D]/g, '"').trim();

let title = 'Summary';
let bullets = [];

try {
  const obj = JSON.parse(s);
  title = obj.title || 'Summary';
  bullets = Array.isArray(obj.bullets) ? obj.bullets : [];
} catch (e) {
  try {
    let fixed = s.replace(/,\s*]/g, ']').replace(/,\s*}/g, '}');
    const obj = JSON.parse(fixed);
    title = obj.title || 'Summary';
    bullets = Array.isArray(obj.bullets) ? obj.bullets : [];
  } catch (e2) {
    try {
      let repair = s;
      const openBrackets = (repair.match(/\[/g) || []).length;
      const closeBrackets = (repair.match(/\]/g) || []).length;
      const openBraces = (repair.match(/\{/g) || []).length;
      const closeBraces = (repair.match(/\}/g) || []).length;
      const quotes = repair.match(/(?<!\\)"/g) || [];
      if (quotes.length % 2 !== 0) repair += '"';
      for (let i = 0; i < (openBrackets - closeBrackets); i++) repair += ']';
      for (let i = 0; i < (openBraces - closeBraces); i++) repair += '}';
      repair = repair.replace(/,\s*]/g, ']').replace(/,\s*}/g, '}');
      const obj = JSON.parse(repair);
      title = obj.title || 'Summary';
      bullets = Array.isArray(obj.bullets) ? obj.bullets : [];
    } catch (e3) {
      try {
        const tm = s.match(/"title"\s*:\s*"((?:[^"\\]|\\.)*)"/);
        if (tm) title = tm[1].replace(/\\"/g, '"').replace(/\\n/g, ' ');
        const bulletsStart = s.indexOf('"bullets"');
        if (bulletsStart > -1) {
          const afterBullets = s.substring(bulletsStart);
          const bracketStart = afterBullets.indexOf('[');
          if (bracketStart > -1) {
            const bulletsContent = afterBullets.substring(bracketStart + 1);
            const completeStrings = [];
            let inString = false;
            let current = '';
            let escaped = false;
            for (let i = 0; i < bulletsContent.length; i++) {
              const ch = bulletsContent[i];
              if (escaped) { current += ch; escaped = false; continue; }
              if (ch === '\\') { current += ch; escaped = true; continue; }
              if (ch === '"') {
                if (inString) {
                  if (current.length > 25) completeStrings.push(current.replace(/\\"/g, '"').replace(/\\n/g, ' '));
                  current = ''; inString = false;
                } else {
                  inString = false; current = ''; inString = true;
                }
              } else if (inString) current += ch;
            }
            if (completeStrings.length > 0) bullets = completeStrings;
          }
        }
      } catch (e4) {
        const tm = s.match(/"title"\s*:\s*"((?:[^"\\]|\\.)*)"/);
        const bm = s.match(/"bullets"\s*:\s*\[([\s\S]*?)\]/);
        if (tm) title = tm[1];
        if (bm) bullets = [...bm[1].matchAll(/"((?:[^"\\]|\\.){10,})"/g)].map(m => m[1]).filter(b => b.length > 15);
      }
    }
  }
}

title = decodeEntities(title);

bullets = bullets
  .map(b => {
    let cleaned = String(b)
      .replace(/^[•\-\s]+/, '')
      .replace(/\s*•\s*/g, ' ')
      .replace(/\.{2,}/g, '.')
      .replace(/\s+/g, ' ')
      .replace(/\\n/g, ' ')
      .replace(/\\"/g, '"')
      .trim();
    return decodeEntities(cleaned);
  })
  .filter(b => {
    if (!b || b.length < 25) return false;
    const lc = b.toLowerCase();
    return !lc.includes('no further details') && !lc.includes('no additional details') &&
           !lc.includes('לא נמצאו פרטים') && !lc.includes('אין פרטים') &&
           !lc.includes('информация недоступна');
  });

if (bullets.length === 0) {
  const noContent = { he: 'לא הצלחתי לחלץ מידע מהמאמר', ru: 'Не удалось извлечь информацию', en: 'Could not extract summary from article' };
  return [{ json: { text: `⚠️ ${noContent[language] || noContent.en}`, slack_channel, slack_ts, slack_thread_ts } }];
}

const PADDING_PATTERNS = [
  /\s*This\s+(strategic|operational|fiscal|historical|massive|directive|depletion|transition|situation|shift|outreach|move|decision|availability|technical|effort|release|step|approach|new\s+generation|latest\s+\w+)\s+\S+[^.!?]*[.!?]/gi,
  /\s*This\s+\w+\s+(aims|seeks|intends|ensures|serves|supports|highlights|mirrors|positions|reflects|demonstrates|underscores|represents|illustrates|facilitates|creates|introduces|marks|signals|offers)\s+[^.!?]*[.!?]/gi,
  /\s*Such\s+(a|an)\s+\S+\s+(would|will|serves|reflects|demonstrates|transforms|ensures)\s+[^.!?]*[.!?]/gi,
  /\s*These\s+\S+\s+(ensure|ensures|serve|serves|support|supports|reflect|reflects)\s+[^.!?]*[.!?]/gi,
  /\s*The\s+(company|article|report)\s+(continues|aims|seeks)\s+[^.!?]*[.!?]/gi,
  /\s*Future\s+developments\s+[^.!?]*[.!?]/gi,
  /\s*(מהלך|צעד|שינוי|מעבר|מצב|החלטה)\s+זה\s+[^.!?]*[.!?]/g,
  /\s*מדובר\s+ב\S*\s+(חשוב|משמעותי|אסטרטגי|היסטורי)[^.!?]*[.!?]/g,
  /\s*בכך\s+\S+\s+(מחזקת|מבטיח|מדגיש)[^.!?]*[.!?]/g,
  /\s*(Это|Данный|Такой)\s+(стратегическое|стратегический|шаг|решение|подход|изменение|переход|сдвиг)\s+[^.!?]*[.!?]/g
];

bullets = bullets.map(b => {
  let cleaned = b;
  for (const rx of PADDING_PATTERNS) cleaned = cleaned.replace(rx, '');
  cleaned = cleaned.replace(/\s+/g, ' ').trim();
  if (cleaned && !/[.!?]$/.test(cleaned)) cleaned += '.';
  return cleaned;
}).filter(b => b.length > 25);

if (bullets.length === 0) {
  const noContent = { he: 'לא נותר תוכן לאחר סינון', ru: 'После фильтрации контент не остался', en: 'No content remaining after filtering' };
  return [{ json: { text: `⚠️ ${noContent[language] || noContent.en}`, slack_channel, slack_ts, slack_thread_ts } }];
}

try {
  const staticData = $getWorkflowStaticData('global');
  if (!staticData.processedUrls) staticData.processedUrls = {};
  staticData.processedUrls[url] = Date.now();
} catch (e) {}

const RLM = '\u200F';
const LRM = '\u200E';
const wrapLatin = t => {
  const protectd = t.replace(/([\u0590-\u05FF]+["'״׳\u05F3\u05F4][\u0590-\u05FF]+)/g, (m) => `\x01${m}\x01`);
  const wrapped = protectd.replace(/([A-Za-z0-9]{2,}(?:[.,:/\-][A-Za-z0-9]+)*)/g, `${LRM}$1${LRM}`);
  return wrapped.replace(/\x01/g, '');
};

let titleLine, bulletLines;

if (language === 'he') {
  const wt = url ? `<${url}|${wrapLatin(title)}>` : wrapLatin(title);
  titleLine = `${RLM}סיכום: ${wt}`;
  bulletLines = bullets.map(b => `${RLM}• ${wrapLatin(b)}`);
} else if (language === 'ru') {
  titleLine = url ? `Резюме: <${url}|${title}>` : `Резюме: ${title}`;
  bulletLines = bullets.map(b => `• ${b}`);
} else {
  titleLine = url ? `Summary: <${url}|${title}>` : `Summary: ${title}`;
  bulletLines = bullets.map(b => `• ${b}`);
}

return [{ json: { text: titleLine + '\n\n' + bulletLines.join('\n\n'), slack_channel, slack_ts, slack_thread_ts } }];

const err = $json.error || 'Unknown error';
const url = $json.url || '';
const lang = $json.language || 'en';
const slack_channel = $json.slack_channel || '';
const slack_ts = $json.slack_ts || '';
const slack_thread_ts = $json.slack_thread_ts || null;

try {
  const staticData = $getWorkflowStaticData('global');
